#include <bits/stdc++.h>
using namespace std;
const int N=5e5+10;
int n,m,a[N],c[N],t[N];
int lowbit(int x){
	return x&(-x);
}
void add(int p,int k){
	if(p>n)
		return;
	t[p]+=k;
	add(p+lowbit(p),k);
}
int sum(int p){
	if(p==0)
		return 0;
	return t[p]+sum(p-lowbit(p));
}
int main(){
	scanf("%d%d",&n,&m);
	for(int i=1;i<=n;i++){
		scanf("%d",&a[i]);
		c[i]=a[i]-a[i-1],t[i]=a[i]-a[i-lowbit(i)];
	}
	while(m--){
		int tp,x,y,k;
		scanf("%d",&tp);
		if(tp==1){
			scanf("%d%d%d",&x,&y,&k);
			add(x,k);
			add(y+1,-k);
		}else{
			scanf("%d",&x);
			printf("%d\n",sum(x));
		}
	}
	return 0;
}
